{
  "name": "SINU - Simulação Interna das Nações Unidas",
  "description": "Landing page oficial para a simulação escolar modelo ONU, com agenda, comitês e assistente diplomático IA."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Committee {
  id: string;
  name: string;
  topic: string;
  level: 'Iniciante' | 'Intermediário' | 'Avançado';
  iconName: string;
  description: string;
}

export interface ScheduleItem {
  time: string;
  activity: string;
  location: string;
}

export interface DaySchedule {
  day: string;
  date: string;
  items: ScheduleItem[];
}

export interface ChatMessage {
  id: string;
  role: 'user' | 'model';
  text: string;
  isStreaming?: boolean;
}

import { GoogleGenAI } from "@google/genai";

const apiKey = process.env.API_KEY || '';
// Initialize conditionally to prevent crashes if key is missing during dev, 
// though strict adherence requires process.env.API_KEY usage.
const ai = new GoogleGenAI({ apiKey });

export const streamDiplomaticAdvice = async (
  userMessage: string, 
  onChunk: (text: string) => void
): Promise<void> => {
  if (!apiKey) {
    onChunk("Erro: Chave de API não configurada. Por favor, configure a API_KEY.");
    return;
  }

  try {
    const model = 'gemini-3-flash-preview';

    // Using chat to maintain a bit of context if needed, but here simple content gen is fine.
    // We use generateContentStream for a single turn response.
    const responseStream = await ai.models.generateContentStream({
      model: model,
      contents: [
        {
          role: 'user',
          parts: [{ text: userMessage }]
        }
      ],
      config: {
        systemInstruction: `Você é um "Diplomata Sênior" e mentor da SINU (Simulação Interna das Nações Unidas). 
        Seu objetivo é ajudar estudantes do ensino médio a entenderem como funciona uma simulação da ONU.
        Seja formal, encorajador, mas acessível. 
        Responda perguntas sobre: Regras de Procedimento, como escrever um DPO (Documento de Posição Oficial), oratória, e termos como 'Ponto de Ordem' ou 'Moção'.
        Mantenha as respostas concisas (máximo 3 parágrafos) para caber num chat widget.`,
      }
    });

    for await (const chunk of responseStream) {
      if (chunk.text) {
        onChunk(chunk.text);
      }
    }
  } catch (error) {
    console.error("Gemini Error:", error);
    onChunk("\n[Perdão, houve uma falha na comunicação diplomática. Tente novamente.]");
  }
};

import React, { useState, useEffect } from 'react';
import { Menu, X, Globe } from 'lucide-react';

const Navbar: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [scrolled, setScrolled] = useState(false);

  useEffect(() => {
    const handleScroll = () => {
      setScrolled(window.scrollY > 20);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const navLinks = [
    { name: 'Sobre', href: '#sobre' },
    { name: 'Comitês', href: '#comites' },
    { name: 'Agenda', href: '#agenda' },
    { name: 'Inscrição', href: '#inscricao' },
  ];

  return (
    <nav className={`fixed w-full z-50 transition-all duration-300 ${scrolled ? 'bg-white shadow-md py-2' : 'bg-transparent py-4'}`}>
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex justify-between items-center">
          {/* Logo */}
          <div className="flex items-center space-x-2">
            <Globe className={`h-8 w-8 ${scrolled ? 'text-un-blue' : 'text-white'}`} />
            <span className={`text-2xl font-serif font-bold ${scrolled ? 'text-un-dark' : 'text-white'}`}>SINU</span>
          </div>

          {/* Desktop Menu */}
          <div className="hidden md:flex space-x-8">
            {navLinks.map((link) => (
              <a
                key={link.name}
                href={link.href}
                className={`text-sm font-semibold uppercase tracking-wider hover:text-un-accent transition-colors ${scrolled ? 'text-slate-600' : 'text-white/90'}`}
              >
                {link.name}
              </a>
            ))}
          </div>

          {/* Mobile Button */}
          <div className="md:hidden flex items-center">
            <button
              onClick={() => setIsOpen(!isOpen)}
              className={`${scrolled ? 'text-slate-800' : 'text-white'} hover:text-un-accent focus:outline-none`}
            >
              {isOpen ? <X className="h-6 w-6" /> : <Menu className="h-6 w-6" />}
            </button>
          </div>
        </div>
      </div>

      {/* Mobile Menu */}
      {isOpen && (
        <div className="md:hidden bg-white shadow-xl absolute w-full top-full left-0 border-t border-slate-100">
          <div className="px-4 pt-2 pb-6 space-y-1">
            {navLinks.map((link) => (
              <a
                key={link.name}
                href={link.href}
                onClick={() => setIsOpen(false)}
                className="block px-3 py-3 text-base font-medium text-slate-700 hover:text-un-blue hover:bg-slate-50 rounded-md"
              >
                {link.name}
              </a>
            ))}
          </div>
        </div>
      )}
    </nav>
  );
};

export default Navbar;

